external_knowledge:
- "Most popular" means videos that have been watched the most times; 
- "the top few" refers to the top 5 videos in each category based on the watch count. 
- The term "popular" implies high frequency of being watched.

sql:
SELECT COUNT(DISTINCT user_id) AS unique_users_watched_more_than_30_minutes
FROM watch_instances
WHERE watched_duration > 1800;

SELECT COUNT(*) AS total_watch_instances
FROM watch_instances
WHERE user_id = 1;

SELECT title, duration
FROM videos
ORDER BY title ASC;

SELECT AVG(watched_duration) AS average_watched_duration
FROM watch_instances
WHERE device_type = 'Mobile';

SELECT name
FROM users
WHERE user_id IN (
    SELECT user_id
    FROM watch_instances
);
